-- =============================================================================
-- oai_db_64ues.sql
-- Populates the OAI 5G Core MySQL database (oai_db) with 64 UE subscribers:
--   - AuthenticationSubscription (SUPI/AKA credentials, Milenage)
--   - SessionManagementSubscriptionData (slice, DNNs oai + ims, static IPv4 on oai)
--
-- UE identifiers: 001010000000001 .. 001010000000064 (15-digit SUPI).
-- Static address on DNN oai: 10.0.0.(UE_index + 1)  e.g. UE 1 -> 10.0.0.2.
--
-- Load example:
--   docker exec -i mysql mysql -u root -plinux oai_db < oai_db_64ues.sql
-- =============================================================================

USE `oai_db`;

-- Remove any existing rows for these subscribers to avoid duplicate key errors.
DELETE FROM `AuthenticationSubscription`
  WHERE `ueid` BETWEEN '001010000000001' AND '001010000000064';

DELETE FROM `SessionManagementSubscriptionData`
  WHERE `servingPlmnid` = '00101'
    AND `ueid` BETWEEN '001010000000001' AND '001010000000064';

INSERT INTO `AuthenticationSubscription` (
  `ueid`, `authenticationMethod`, `encPermanentKey`, `protectionParameterId`,
  `sequenceNumber`, `authenticationManagementField`, `algorithmId`, `encOpcKey`,
  `encTopcKey`, `vectorGenerationInHss`, `n5gcAuthMethod`, `rgAuthenticationInd`, `supi`
) VALUES
